5774       if (!match(OpVal, m_ZExtOrSExt(m_VPValue(ExtInput))) &&
5775           !match(OpVal, m_FPExt(m_VPValue(ExtInput))))
5776         return false;
5777 
5778       CastRecipes[I] = dyn_cast<VPWidenCastRecipe>(OpVal);
5779       if (!CastRecipes[I])
5780         return false;
5781 
5782       // The outer extend kind must match the inner extends for folding.
5783       if (OuterExtKind) {
5784         auto CastOp =
5785             static_cast<Instruction::CastOps>(CastRecipes[I]->getOpcode());
5786         if (*OuterExtKind != TTI::getPartialReductionExtendKind(CastOp))
5787           return false;
5788       }
5789     }
5790     return CastRecipes[0] != nullptr;
5791   };
5792 
5793   // If Op is a binary operator, check both of its operands to see if they are
5794   // extends. Otherwise, see if the update comes directly from an extend.
5795   auto *BinOp = dyn_cast<VPWidenRecipe>(Op);
5796   if (BinOp && Instruction::isBinaryOp(BinOp->getOpcode())) {
5797     if (!BinOp->hasOneUse())
5798       return false;
5799 
5800     // Handle neg(binop(ext, ext)) pattern.
5801     VPValue *OtherOp = nullptr;
5802     if (match(BinOp, m_Sub(m_ZeroInt(), m_VPValue(OtherOp))))
5803       BinOp = dyn_cast<VPWidenRecipe>(OtherOp);
5804 
5805     if (!BinOp || !Instruction::isBinaryOp(BinOp->getOpcode()) ||
5806         !MatchExtends(BinOp->operands()))
5807       return false;
5808   } else if (match(UpdateR, m_Add(m_VPValue(), m_VPValue())) ||
5809              match(UpdateR, m_FAdd(m_VPValue(), m_VPValue()))) {
5810     // We already know the operands for Update are Op and PhiOp.
5811     if (!MatchExtends({Op}))
5812       return false;
5813     BinOp = UpdateR;
5814   } else {
5815     return false;
5816   }
5817 
5818   Type *PhiType = CostCtx.Types.inferScalarType(RedPhiR);
5819   TypeSize PHISize = PhiType->getPrimitiveSizeInBits();
5820   Type *ExtOpType =
5821       CostCtx.Types.inferScalarType(CastRecipes[0]->getOperand(0));
5822   TypeSize ASize = ExtOpType->getPrimitiveSizeInBits();
5823   if (!PHISize.hasKnownScalarFactor(ASize))
5824     return false;
5825 
5826   VPPartialReductionChain Chain(
5827       {UpdateR, CastRecipes[0], CastRecipes[1], BinOp,
5828        static_cast<unsigned>(PHISize.getKnownScalarFactor(ASize))});
5829   if (!isValidPartialReduction(Chain, PhiType, CostCtx, Range))
5830     return false;
5831 
5832   Chains.push_back(Chain);
5833   return true;
5834 }
