5837 void VPlanTransforms::createPartialReductions(VPlan &Plan,
5838                                               VPCostContext &CostCtx,
5839                                               VFRange &Range) {
5840   // Find all possible valid partial reductions, grouping chains by their PHI.
5841   // This grouping allows invalidating the whole chain, if any link is not a
5842   // valid partial reduction.
5843   MapVector<VPReductionPHIRecipe *, SmallVector<VPPartialReductionChain>>
5844       ChainsByPhi;
5845   VPBasicBlock *HeaderVPBB = Plan.getVectorLoopRegion()->getEntryBasicBlock();
5846   for (VPRecipeBase &R : HeaderVPBB->phis()) {
5847     auto *RedPhiR = dyn_cast<VPReductionPHIRecipe>(&R);
5848     if (!RedPhiR)
5849       continue;
5850 
5851     // Get the backedge value from the reduction PHI and find the
5852     // ComputeReductionResult that uses it (directly or through a select for
5853     // predicated reductions).
5854     if (auto *RdxResult = vputils::findComputeReductionResult(RedPhiR)) {
5855       VPValue *ExitValue = RdxResult->getOperand(0);
5856       match(ExitValue,
5857             m_Select(m_VPValue(), m_VPValue(ExitValue), m_VPValue()));
5858       getScaledReductions(RedPhiR, ExitValue, ChainsByPhi[RedPhiR], CostCtx,
5859                           Range);
5860     }
5861   }
5862 
5863   if (ChainsByPhi.empty())
5864     return;
5865 
5866   // Build set of partial reduction operations for extend user validation and
5867   // a map of reduction bin ops to their scale factors for scale validation.
5868   SmallPtrSet<VPRecipeBase *, 4> PartialReductionOps;
5869   DenseMap<VPSingleDefRecipe *, unsigned> ScaledReductionMap;
5870   for (const auto &[_, Chains] : ChainsByPhi)
5871     for (const VPPartialReductionChain &Chain : Chains) {
5872       PartialReductionOps.insert(Chain.BinOp);
5873       ScaledReductionMap[Chain.ReductionBinOp] = Chain.ScaleFactor;
5874     }
5875 
5876   // A partial reduction is invalid if any of its extends are used by
5877   // something that isn't another partial reduction. This is because the
5878   // extends are intended to be lowered along with the reduction itself.
5879   auto ExtendUsersValid = [&](VPWidenCastRecipe *Ext) {
5880     return !Ext || all_of(Ext->users(), [&](VPUser *U) {
5881       return PartialReductionOps.contains(cast<VPRecipeBase>(U));
5882     });
5883   };
5884 
5885   // Validate chains: check that extends are only used by partial reductions,
5886   // and that reduction bin ops are only used by other partial reductions with
5887   // matching scale factors, are outside the loop region or the select
5888   // introduced by tail-folding. Otherwise we would create users of scaled
5889   // reductions where the types of the other operands don't match.
5890   for (auto &[RedPhiR, Chains] : ChainsByPhi) {
5891     for (const VPPartialReductionChain &Chain : Chains) {
5892       if (!ExtendUsersValid(Chain.ExtendA) ||
5893           !ExtendUsersValid(Chain.ExtendB)) {
5894         Chains.clear();
5895         break;
5896       }
5897       auto UseIsValid = [&, RedPhiR = RedPhiR](VPUser *U) {
5898         if (auto *PhiR = dyn_cast<VPReductionPHIRecipe>(U))
5899           return PhiR == RedPhiR;
5900         auto *R = cast<VPSingleDefRecipe>(U);
5901         return Chain.ScaleFactor == ScaledReductionMap.lookup_or(R, 0) ||
5902                match(R, m_ComputeReductionResult(
5903                             m_Specific(Chain.ReductionBinOp))) ||
5904                match(R, m_Select(m_VPValue(), m_Specific(Chain.ReductionBinOp),
5905                                  m_Specific(RedPhiR)));
5906       };
5907       if (!all_of(Chain.ReductionBinOp->users(), UseIsValid)) {
5908         Chains.clear();
5909         break;
5910       }
5911 
5912       // Check if the compute-reduction-result is used by a sunk store.
5913       // TODO: Also form partial reductions in those cases.
5914       if (auto *RdxResult = vputils::findComputeReductionResult(RedPhiR)) {
5915         if (any_of(RdxResult->users(), [](VPUser *U) {
5916               auto *RepR = dyn_cast<VPReplicateRecipe>(U);
5917               return RepR && isa<StoreInst>(RepR->getUnderlyingInstr());
5918             })) {
5919           Chains.clear();
5920           break;
5921         }
5922       }
5923     }
5924   }
5925 
5926   for (auto &[Phi, Chains] : ChainsByPhi) {
5927     RecurKind RK = cast<VPReductionPHIRecipe>(Phi)->getRecurrenceKind();
5928     for (const VPPartialReductionChain &Chain : Chains)
5929       transformToPartialReduction(Chain, CostCtx.Types, Plan, Phi, RK);
5930   }
5931 }
