5549 // Helper to transform a partial reduction chain into a partial reduction
5550 // recipe. Assumes profitability has been checked.
5551 static void transformToPartialReduction(const VPPartialReductionChain &Chain,
5552                                         VPTypeAnalysis &TypeInfo, VPlan &Plan,
5553                                         VPReductionPHIRecipe *RdxPhi,
5554                                         RecurKind RK) {
5555   VPWidenRecipe *WidenRecipe = Chain.ReductionBinOp;
5556   assert(WidenRecipe->getNumOperands() == 2 && "Expected binary operation");
5557 
5558   VPValue *BinOp = WidenRecipe->getOperand(0);
5559   VPValue *Accumulator = WidenRecipe->getOperand(1);
5560 
5561   // Swap if needed to ensure Accumulator is the PHI or partial reduction.
5562   if (isa_and_present<VPReductionPHIRecipe, VPReductionRecipe>(BinOp))
5563     std::swap(BinOp, Accumulator);
5564 
5565   // Sub-reductions can be implemented in two ways:
5566   // (1) negate the operand in the vector loop (the default way).
5567   // (2) subtract the reduced value from the init value in the middle block.
5568   // Both ways keep the reduction itself as an 'add' reduction.
5569   //
5570   // The ISD nodes for partial reductions don't support folding the
5571   // sub/negation into its operands because the following is not a valid
5572   // transformation:
5573   //      sub(0, mul(ext(a), ext(b)))
5574   //   -> mul(ext(a), ext(sub(0, b)))
5575   //
5576   // It's therefore better to choose option (2) such that the partial
5577   // reduction is always positive (starting at '0') and to do a final
5578   // subtract in the middle block.
5579   if (WidenRecipe->getOpcode() == Instruction::Sub && RK != RecurKind::Sub) {
5580     VPBuilder Builder(WidenRecipe);
5581     Type *ElemTy = TypeInfo.inferScalarType(BinOp);
5582     auto *Zero = Plan.getConstantInt(ElemTy, 0);
5583     VPIRFlags Flags = WidenRecipe->getUnderlyingInstr()
5584                           ? VPIRFlags(*WidenRecipe->getUnderlyingInstr())
5585                           : VPIRFlags();
5586     auto *NegRecipe = new VPWidenRecipe(Instruction::Sub, {Zero, BinOp}, Flags,
5587                                         VPIRMetadata(), DebugLoc::getUnknown());
5588     Builder.insert(NegRecipe);
5589     BinOp = NegRecipe;
5590   }
5591 
5592   // Check if WidenRecipe is the final result of the reduction. If so look
5593   // through selects for predicated reductions.
5594   VPValue *Cond = nullptr;
5595   VPValue *ExitValue = cast_or_null<VPInstruction>(vputils::findUserOf(
5596       WidenRecipe,
5597       m_Select(m_VPValue(Cond), m_Specific(WidenRecipe), m_Specific(RdxPhi))));
5598   bool IsLastInChain = RdxPhi->getBackedgeValue() == WidenRecipe ||
5599                        RdxPhi->getBackedgeValue() == ExitValue;
5600   assert((!ExitValue || IsLastInChain) &&
5601          "if we found ExitValue, it must match RdxPhi's backedge value");
5602 
5603   Type *PhiType = TypeInfo.inferScalarType(RdxPhi);
5604   RecurKind RdxKind =
5605       PhiType->isFloatingPointTy() ? RecurKind::FAdd : RecurKind::Add;
5606   auto *PartialRed = new VPReductionRecipe(
5607       RdxKind,
5608       RdxKind == RecurKind::FAdd ? WidenRecipe->getFastMathFlags()
5609                                  : FastMathFlags(),
5610       WidenRecipe->getUnderlyingInstr(), Accumulator, BinOp, Cond,
5611       RdxUnordered{/*VFScaleFactor=*/Chain.ScaleFactor});
5612   PartialRed->insertBefore(WidenRecipe);
5613 
5614   if (Cond)
5615     ExitValue->replaceAllUsesWith(PartialRed);
5616   WidenRecipe->replaceAllUsesWith(PartialRed);
5617 
5618   // We only need to update the PHI node once, which is when we find the
5619   // last reduction in the chain.
5620   if (!IsLastInChain)
5621     return;
5622 
5623   // Scale the PHI and ReductionStartVector by the VFScaleFactor
5624   assert(RdxPhi->getVFScaleFactor() == 1 && "scale factor must not be set");
5625   RdxPhi->setVFScaleFactor(Chain.ScaleFactor);
5626 
5627   auto *StartInst = cast<VPInstruction>(RdxPhi->getStartValue());
5628   assert(StartInst->getOpcode() == VPInstruction::ReductionStartVector);
5629   auto *NewScaleFactor = Plan.getConstantInt(32, Chain.ScaleFactor);
5630   StartInst->setOperand(2, NewScaleFactor);
5631 
5632   // If this is the last value in a sub-reduction chain, then update the PHI
5633   // node to start at `0` and update the reduction-result to subtract from
5634   // the PHI's start value.
5635   if (RK != RecurKind::Sub)
5636     return;
5637 
5638   VPValue *OldStartValue = StartInst->getOperand(0);
5639   StartInst->setOperand(0, StartInst->getOperand(1));
5640 
5641   // Replace reduction_result by 'sub (startval, reductionresult)'.
5642   VPInstruction *RdxResult = vputils::findComputeReductionResult(RdxPhi);
5643   assert(RdxResult && "Could not find reduction result");
5644 
5645   VPBuilder Builder = VPBuilder::getToInsertAfter(RdxResult);
5646   constexpr unsigned SubOpc = Instruction::BinaryOps::Sub;
5647   VPInstruction *NewResult = Builder.createNaryOp(
5648       SubOpc, {OldStartValue, RdxResult}, VPIRFlags::getDefaultFlags(SubOpc),
5649       RdxPhi->getDebugLoc());
5650   RdxResult->replaceUsesWithIf(
5651       NewResult,
5652       [&NewResult](VPUser &U, unsigned Idx) { return &U != NewResult; });
5653 }
