5714 static bool
5715 getScaledReductions(VPSingleDefRecipe *RedPhiR, VPValue *PrevValue,
5716                     SmallVectorImpl<VPPartialReductionChain> &Chains,
5717                     VPCostContext &CostCtx, VFRange &Range) {
