5710 /// Examines reduction operations to see if the target can use a cheaper
5711 /// operation with a wider per-iteration input VF and narrower PHI VF.
5712 /// Recursively calls itself to identify chained scaled reductions.
5713 /// Returns true if this invocation added an entry to Chains, otherwise false.
5714 static bool
5715 getScaledReductions(VPSingleDefRecipe *RedPhiR, VPValue *PrevValue,
5716                     SmallVectorImpl<VPPartialReductionChain> &Chains,
5717                     VPCostContext &CostCtx, VFRange &Range) {
5718   auto *UpdateR = dyn_cast<VPWidenRecipe>(PrevValue);
5719   if (!UpdateR || !Instruction::isBinaryOp(UpdateR->getOpcode()))
5720     return false;
5721 
5722   VPValue *Op = UpdateR->getOperand(0);
5723   VPValue *PhiOp = UpdateR->getOperand(1);
5724   if (Op == RedPhiR)
5725     std::swap(Op, PhiOp);
5726 
5727   // If Op is an extend, then it's still a valid partial reduction if the
5728   // extended mul fulfills the other requirements.
5729   // For example, reduce.add(ext(mul(ext(A), ext(B)))) is still a valid partial
5730   // reduction since the inner extends will be widened. We already have oneUse
5731   // checks on the inner extends so widening them is safe.
5732   std::optional<TTI::PartialReductionExtendKind> OuterExtKind;
5733   if (match(Op, m_ZExtOrSExt(m_Mul(m_VPValue(), m_VPValue()))) ||
5734       match(Op, m_FPExt(m_FMul(m_VPValue(), m_VPValue())))) {
5735     auto *CastRecipe = dyn_cast<VPWidenCastRecipe>(Op);
5736     if (!CastRecipe)
5737       return false;
5738     auto CastOp = static_cast<Instruction::CastOps>(CastRecipe->getOpcode());
5739     OuterExtKind = TTI::getPartialReductionExtendKind(CastOp);
5740     Op = CastRecipe->getOperand(0);
5741   }
5742 
5743   // Try and get a scaled reduction from the first non-phi operand.
5744   // If one is found, we use the discovered reduction instruction in
5745   // place of the accumulator for costing.
5746   if (getScaledReductions(RedPhiR, Op, Chains, CostCtx, Range)) {
5747     RedPhiR = Chains.rbegin()->ReductionBinOp;
5748     Op = UpdateR->getOperand(0);
5749     PhiOp = UpdateR->getOperand(1);
5750     if (Op == RedPhiR)
5751       std::swap(Op, PhiOp);
5752   }
5753   if (RedPhiR != PhiOp)
5754     return false;
5755 
5756   // If the update is a binary op, check both of its operands to see if
5757   // they are extends. Otherwise, see if the update comes directly from an
5758   // extend.
5759   VPWidenCastRecipe *CastRecipes[2] = {nullptr};
5760 
5761   // Match extends and populate CastRecipes. Returns false if matching fails.
5762   auto MatchExtends = [OuterExtKind,
5763                        &CastRecipes](ArrayRef<VPValue *> Operands) {
5764     assert(Operands.size() <= 2 && "expected at most 2 operands");
5765 
5766     for (const auto &[I, OpVal] : enumerate(Operands)) {
5767       // Allow constant as second operand - validation happens in
