5655 /// Check if a partial reduction chain is is supported by the target (i.e. does
5656 /// not have an invalid cost) for the given VF range. Clamps the range and
5657 /// returns true if profitable for any VF.
5658 static bool isValidPartialReduction(const VPPartialReductionChain &Chain,
5659                                     Type *PhiType, VPCostContext &CostCtx,
5660                                     VFRange &Range) {
5661   auto GetExtInfo = [&CostCtx](VPWidenCastRecipe *Ext)
5662       -> std::pair<Type *, TargetTransformInfo::PartialReductionExtendKind> {
5663     if (!Ext)
5664       return {nullptr, TargetTransformInfo::PR_None};
5665     Type *ExtOpType = CostCtx.Types.inferScalarType(Ext->getOperand(0));
5666     auto ExtKind = TargetTransformInfo::getPartialReductionExtendKind(
5667         static_cast<Instruction::CastOps>(Ext->getOpcode()));
5668     return {ExtOpType, ExtKind};
5669   };
5670   auto ExtInfoA = GetExtInfo(Chain.ExtendA);
5671   auto ExtInfoB = GetExtInfo(Chain.ExtendB);
5672   Type *ExtOpTypeA = ExtInfoA.first;
5673   Type *ExtOpTypeB = ExtInfoB.first;
5674   auto ExtKindA = ExtInfoA.second;
5675   auto ExtKindB = ExtInfoB.second;
5676 
5677   // If ExtendB is nullptr but there's a separate BinOp, the second operand
5678   // was a constant that can use the same extend kind as the first.
5679   if (!Chain.ExtendB && Chain.BinOp && Chain.BinOp != Chain.ReductionBinOp) {
5680     const APInt *Const = nullptr;
5681     for (VPValue *Op : Chain.BinOp->operands()) {
5682       if (match(Op, m_APInt(Const)))
5683         break;
5684     }
5685     if (!Const || !canConstantBeExtended(Const, ExtOpTypeA, ExtKindA))
5686       return false;
5687     ExtOpTypeB = ExtOpTypeA;
5688     ExtKindB = ExtKindA;
5689   }
5690 
5691   std::optional<unsigned> BinOpc =
5692       (Chain.BinOp && Chain.BinOp != Chain.ReductionBinOp)
5693           ? std::make_optional(Chain.BinOp->getOpcode())
5694           : std::nullopt;
5695   VPWidenRecipe *WidenRecipe = Chain.ReductionBinOp;
5696   return LoopVectorizationPlanner::getDecisionAndClampRange(
5697       [&](ElementCount VF) {
5698         return CostCtx.TTI
5699             .getPartialReductionCost(
5700                 WidenRecipe->getOpcode(), ExtOpTypeA, ExtOpTypeB, PhiType, VF,
5701                 ExtKindA, ExtKindB, BinOpc, CostCtx.CostKind,
5702                 PhiType->isFloatingPointTy()
5703                     ? std::optional{WidenRecipe->getFastMathFlags()}
5704                     : std::nullopt)
5705             .isValid();
5706       },
5707       Range);
5708 }
